using System;
using System.Linq;
using System.Reflection;

var asm = Assembly.LoadFrom(
    Path.Combine(
        Environment.GetFolderPath(Environment.SpecialFolder.UserProfile),
        ".nuget/packages/xunit.v3.extensibility.core/3.2.2/lib/netstandard2.0/xunit.v3.core.dll"));
var type = asm.GetType("Xunit.v3.ITestCaseOrderer");
if (type != null)
{
    foreach (var m in type.GetMethods())
    {
        Console.WriteLine($"Method: {m}");
        if (m.IsGenericMethod)
        {
            foreach (var gp in m.GetGenericArguments())
            {
                var constraints = gp.GetGenericParameterConstraints();
                Console.WriteLine($"  {gp.Name} constraints: [{string.Join(", ", constraints.Select(c => c.FullName ?? c.Name))}]");
                Console.WriteLine($"  Attributes: {gp.GenericParameterAttributes}");
            }
        }
    }
}
else
{
    Console.WriteLine("Type not found. Available types with 'Orderer':");
    foreach (var t in asm.GetTypes().Where(t => t.Name.Contains("Orderer")))
        Console.WriteLine($"  {t.FullName}");
}
CSEOF
